#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <omp.h>

#define DIM 4096
#define TSTEPS 1000

void copy(double *src, double *dst, int n) {
#pragma omp parallel for
  for (int i = 0; i < n; i++) {
    dst[i] = src[i];
  }
}

int main() {
  double (*A)[DIM] = (double (*)[DIM])malloc(sizeof(double) * DIM * DIM);
  double (*B)[DIM] = (double (*)[DIM])malloc(sizeof(double) * DIM * DIM);

  // Initialize arrays
#pragma omp parallel for collapse(2)
  for (int i = 0; i < DIM; i++) {
    for (int j = 0; j < DIM; j++) {
      A[i][j] = 0.0;
      B[i][j] = 0.0;
    }
  }

  // Set initial condition: a hot spot in the middle
  A[DIM / 2][DIM / 2] = 1000.0;

  for (int t = 0; t < TSTEPS; t++) {
    // Update B from A (excluding boundaries)
#pragma omp parallel for collapse(2)
    for (int i = 1; i < DIM - 1; i++) {
      for (int j = 1; j < DIM - 1; j++) {
        B[i][j] = 0.25 * (A[i + 1][j] + A[i - 1][j] + A[i][j + 1] + A[i][j - 1]);
      }
    }

    // Update A from B (excluding boundaries)
#pragma omp parallel for collapse(2)
    for (int i = 1; i < DIM - 1; i++) {
      for (int j = 1; j < DIM - 1; j++) {
        A[i][j] = 0.25 * (B[i + 1][j] + B[i - 1][j] + B[i][j + 1] + B[i][j - 1]);
      }
    }
  }

  // Print the center value
  printf("Center value: %f\n", A[DIM / 2][DIM / 2]);

  free(A);
  free(B);

  return 0;
}
